def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        decay = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.03 + 0.015 * j
            elif j % 6 == 0:
                multiplier *= 0.92 - 0.007 * j
            elif j % 7 == 0:
                multiplier *= 1.08 + 0.005 * j
            if ratio < 0.08 * j:
                score += (j ** 3) / (1 + np.exp(ratio * j)) * multiplier
            else:
                score += (np.sqrt(j*j*j) + np.tanh(ratio * j)) * multiplier / (j + 1)
            if (cap * j + j*j) % 11 == 0:
                score *= 1.06
            elif (cap + item * j) % 9 == 0:
                score *= 0.94
            if j in {5, 10}:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.75 and j % 3 == 0:
                adjustment *= 1.12 + 0.025 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.02 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * 1.5) * 0.6
            decay *= 1.0 / (1.0 + 0.01 * j * ratio)
        score += penalty * 0.75
        score *= adjustment * decay
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.sin(ratio * np.pi))
        else:
            if cap > item * 3.5 and ratio < 0.85:
                priorities[i] = -score / (np.sqrt(cap) + 1) * (1 + ratio)**1.1
            elif cap <= item * 3.5 and ratio >= 0.85:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**3)
            else:
                priorities[i] = -score / (cap + 2) * np.exp(-0.5 * ratio**2)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 3 == 1:
            priorities[i] *= 1.04
        else:
            priorities[i] *= 1.01
        if i % 2 == 0:
            priorities[i] *= 0.99 + 0.005 * (item % 1)
        else:
            priorities[i] *= 1.01 - 0.004 * (item % 1)
    return priorities
